from datetime import datetime, timedelta
import json

class User(object):

    def __init__(self):
        self.username = ""  # required
        self.password_hash = None
        self.token = None
        self.token_expiration = None

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def generate_token(self, expiration=3600):
        self.token = b64encode(urandom(24)).decode('utf-8')
        self.token_expiration = datetime.utcnow() + timedelta(seconds=expiration)
        return self.token

    def verify_token(self, token):
        if self.token != token:
            return False
        if datetime.utcnow() > self.token_expiration:
            return False
        return True

    def to_dict(self):
        return {
            'username': self.username,
            'password_hash': self.password_hash,
            'token': self.token,
            'token_expiration': self.token_expiration.isoformat() if self.token_expiration else None
        }

    def save(self):
        key = f'user:{self.username}'
        redis_db.set(key, json.dumps(self.to_dict()))

    @classmethod
    def load(cls, username):
        key = f'user:{username}'
        data = redis_db.get(key)
        if not data:
            return None
        obj = cls()
        obj.username = username
        d = json.loads(data)
        obj.password_hash = d.get('password_hash')
        obj.token = d.get('token')
        exp = d.get('token_expiration')
        obj.token_expiration = datetime.fromisoformat(exp) if exp else None
        return obj

